    if not issues:
        return {"pass": True, "score": 1.0, "feedback": f"Row 5 in dock_schedule.xlsx matches all expected values: {[normalize(v) for v in row_values[:15]]}"}
    else:
        return {"pass": False, "score": 0.0, "feedback": f"Row 5 in dock_schedule.xlsx has issues: {'; '.join(issues)}. Actual row values: {row_values[:15]}"}

from pathlib import Path
import openpyxl
import re
from datetime import datetime

def verify(workspace_path, external_services_path=None):
    file_path = Path(workspace_path) / "open_pos.xlsx"
    if not file_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"File 'open_pos.xlsx' not found in workspace: {workspace_path}"}

    try:
        wb = openpyxl.load_workbook(str(file_path))
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not open 'open_pos.xlsx': {e}"}

    ws = wb.active

    row_5 = []
    for cell in ws[5]:
        row_5.append(cell.value)

    # Remove trailing None values
    while row_5 and row_5[-1] is None:
        row_5 = row_5[:-1]

    # Expected values (20 columns):
    # MER-PO-204871 | 001 | 10/31/2026 | 11/28/2026 | SUP-0147 | Vantage Lubricants Inc. | FL-08814-A1 | Gear oil, ISO VG 220, 20L drum | 24 | $38.50 | N | N | FL-08814-A0, FL-08814-A2, FL-08814-A3 | (empty) | (empty) | (empty) | (empty) | N | N | Open

    expected = [
        "MER-PO-204871",
        "001",
        "10/31/2026",
        "11/28/2026",
        "SUP-0147",
        "Vantage Lubricants Inc.",
        "FL-08814-A1",
        "Gear oil, ISO VG 220, 20L drum",
        "24",
        "$38.50",
        "N",
        "N",
        "FL-08814-A0, FL-08814-A2, FL-08814-A3",
        "",
        "",
        "",
        "",
        "N",
        "N",
        "Open"
    ]

    def normalize(val):
        if val is None:
            return ""
        if isinstance(val, datetime):
            return val.strftime("%m/%d/%Y")
        s = str(val).strip()
        return s

    def values_match(actual_val, expected_val):
        a = normalize(actual_val)
        e = expected_val.strip()

        # Both empty
        if a == "" and e == "":
            return True
        if a == "" or e == "":
            # If expected is empty, actual should be empty
            return a == "" and e == ""

        # Case-insensitive comparison
        if a.lower() == e.lower():
            return True

        # Try numeric comparison with tolerance
        def extract_number(s):
            s_clean = re.sub(r'[\$,\s]', '', s)
            try:
                return float(s_clean)
            except ValueError:
                return None

        a_num = extract_number(a)
        e_num = extract_number(e)
        if a_num is not None and e_num is not None:
            if e_num == 0:
                return abs(a_num) < 0.01
            if abs(a_num - e_num) / max(abs(e_num), 0.001) <= 0.05:
                return True

        # For "001" vs "1" or "1.0"
        if e == "001":
            if a in ["001", "1", "1.0"]:
                return True

        # Date comparison: try multiple formats
        date_formats = ["%m/%d/%Y", "%Y-%m-%d", "%m-%d-%Y", "%d/%m/%Y", "%Y/%m/%d", "%m/%d/%y"]
        def parse_date(s):
            for fmt in date_formats:
                try:
                    return datetime.strptime(s, fmt)
                except ValueError:
                    continue
            return None

        a_date = parse_date(a)
        e_date = parse_date(e)
        if a_date and e_date and a_date == e_date:
            return True

        # For the alternates field, compare sets of items
        if "," in e:
            e_parts = set(x.strip().lower() for x in e.split(","))
            a_parts = set(x.strip().lower() for x in a.split(","))
            if e_parts == a_parts:
                return True

        return False

    # Ensure row has enough columns (pad with None if needed)
    while len(row_5) < len(expected):
        row_5.append(None)

    mismatches = []
    matches = 0
    details = []
    for i, (act, exp) in enumerate(zip(row_5[:len(expected)], expected)):
        if values_match(act, exp):
            matches += 1
            details.append(f"  Col {i+1}: OK (actual='{normalize(act)}', expected='{exp}')")
        else:
            mismatches.append(i + 1)
            details.append(f"  Col {i+1}: MISMATCH (actual='{normalize(act)}', expected='{exp}')")

    total = len(expected)
    score = matches / total if total > 0 else 0.0
    passed = len(mismatches) == 0

    detail_str = "\n".join(details)
    if passed:
        feedback = f"PASS: All {total} values in row 5 of open_pos.xlsx match expected values.\n{detail_str}"
    else:
        feedback = f"FAIL: {len(mismatches)} of {total} values in row 5 do not match. Mismatched columns: {mismatches}\n{detail_str}"

    return {"pass": passed, "score": score, "feedback": feedback}
